from collections import deque

def removeInvalidParentheses(data):
    s = (data or "").strip()
    if s == "":
        return "['']"

    def valid(x):
        bal = 0
        for ch in x:
            if ch == "(":
                bal += 1
            elif ch == ")":
                if bal == 0:
                    return False
                bal -= 1
        return bal == 0

    q = deque([s])
    seen = {s}
    found = []
    done = False

    while q and not done:
        for _ in range(len(q)):
            cur = q.popleft()
            if valid(cur):
                found.append(cur)
                done = True
            if done:
                continue
            for i, ch in enumerate(cur):
                if ch not in "()":
                    continue
                nxt = cur[:i] + cur[i + 1:]
                if nxt not in seen:
                    seen.add(nxt)
                    q.append(nxt)

    if not found:
        return "['']"
    found = sorted(set(found))
    return "\n".join(found)

