function removeInvalidParentheses(data) {
    const s = (data || '').trim();
    if (!s) return "['']";

    const isValid = (x) => {
        let bal = 0;
        for (const ch of x) {
            if (ch === '(') bal += 1;
            else if (ch === ')') {
                if (bal === 0) return false;
                bal -= 1;
            }
        }
        return bal === 0;
    };

    const q = [s];
    const seen = new Set([s]);
    const found = [];
    let idx = 0;
    let done = false;

    while (idx < q.length && !done) {
        const levelSize = q.length - idx;
        for (let c = 0; c < levelSize; c++) {
            const cur = q[idx++];
            if (isValid(cur)) {
                found.push(cur);
                done = true;
            }
            if (done) continue;
            for (let i = 0; i < cur.length; i++) {
                const ch = cur[i];
                if (ch !== '(' && ch !== ')') continue;
                const nxt = cur.slice(0, i) + cur.slice(i + 1);
                if (!seen.has(nxt)) {
                    seen.add(nxt);
                    q.push(nxt);
                }
            }
        }
    }

    if (!found.length) return "['']";
    return Array.from(new Set(found)).sort().join('\n');
}

