import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
class Solution {
    public List<String> removeInvalidParentheses(String data) {
        HashSet<String> result = new HashSet<>();
        int[] minRemoved = {
            Integer.MAX_VALUE
        }
        ;
        dfs(data, 0, 0, 0, new StringBuilder(), result, minRemoved);
        return new ArrayList<>(result);
    }
    private void dfs(String data, int index, int leftCount, int rightCount, StringBuilder current, HashSet<String> result, int[] minRemoved) {
        if (index == data.length()) {
            if (leftCount == rightCount) {
                if (current.length() < minRemoved[0]) {
                    minRemoved[0] = current.length();
                    result.clear();
                }
                if (current.length() == minRemoved[0]) {
                    result.add(current.toString());
                }
            }
            return;
        }
        char ch = data.charAt(index);
        int len = current.length();
        if (ch == '(') {
            // Exclude the current '('
            dfs(data, index + 1, leftCount, rightCount, current, result, minRemoved);
            // Include the current '('
            current.append(ch);
            dfs(data, index + 1, leftCount + 1, rightCount, current, result, minRemoved);
            current.setLength(len); // backtrack
        }
        else if (ch == ')') {
            // Exclude the current ')'
            dfs(data, index + 1, leftCount, rightCount, current, result, minRemoved);
            // Include the current ')'
            if (leftCount > rightCount) {
                current.append(ch);
                dfs(data, index + 1, leftCount, rightCount + 1, current, result, minRemoved);
                current.setLength(len); // backtrack
            }
        }
        else {
            // Include non-parenthesis characters
            current.append(ch);
            dfs(data, index + 1, leftCount, rightCount, current, result, minRemoved);
            current.setLength(len); // backtrack
        }
    }
}

