using namespace std;
class Solution {
    public:
    vector<string> removeInvalidParentheses(string data) {
        unordered_set<string> result;
        int leftRemove = 0, rightRemove = 0;
        for (char c : data) {
            if (c == '(') leftRemove++;
            else if (c == ')') {
                if (leftRemove > 0) leftRemove--;
                else rightRemove++;
            }
        }
        string current;
        dfs(data, 0, leftRemove, rightRemove, current, result);
        return vector<string>(result.begin(), result.end());
    }
    private:
    void dfs(string& data, int index, int leftRemove, int rightRemove, string& current, unordered_set<string>& result) {
        if (index == data.size()) {
            if (leftRemove == 0 && rightRemove == 0) {
                result.insert(current);
            }
            return;
        }
        char c = data[index];
        if (c == '(') {
            if (leftRemove > 0) {
                dfs(data, index + 1, leftRemove - 1, rightRemove, current, result);
            }
            current.push_back(c);
            dfs(data, index + 1, leftRemove, rightRemove, current, result);
            current.pop_back();
        }
        else if (c == ')') {
            if (rightRemove > 0) {
                dfs(data, index + 1, leftRemove, rightRemove - 1, current, result);
            }
            current.push_back(c);
            dfs(data, index + 1, leftRemove, rightRemove, current, result);
            current.pop_back();
        }
        else {
            current.push_back(c);
            dfs(data, index + 1, leftRemove, rightRemove, current, result);
            current.pop_back();
        }
    }
}
