package main

import (
    "fmt"
)

func removeInvalidParentheses(data string) []string {
    var result []string
    visited := make(map[string]bool)
    var dfs func(string, int, int, int)

    isValid := func(s string) bool {
        count := 0
        for _, char := range s {
            if char == '(' {
                count++
            } else if char == ')' {
                count--
            }
            if count < 0 {
                return false
            }
        }
        return count == 0
    }

    dfs = func(s string, last_i, last_j, paren_count int) {
        if last_j > len(s) || paren_count < 0 {
            return
        }
        if last_i == len(s) {
            if paren_count == 0 && isValid(s) {
                if !visited[s] {
                    visited[s] = true
                    result = append(result, s)
                }
            }
        } else {
            for i := last_i; i < len(s); i++ {
                if s[i] == '(' {
                    dfs(s[:i]+s[i+1:], i, i, paren_count-1)
                } else if s[i] == ')' {
                    dfs(s[:i]+s[i+1:], i, i, paren_count+1)
                }
            }
            dfs(s, len(s), len(s), paren_count)
        }
    }

    paren_count := 0
    for _, char := range data {
        if char == '(' {
            paren_count++
        } else if char == ')' {
            paren_count--
        }
    }
    if paren_count < 0 {
        paren_count = 0
    }
    dfs(data, 0, 0, paren_count)
    return result
}

func main() {
    data := "(a)())()"
    result := removeInvalidParentheses(data)
    fmt.Println(result)
}

