using System;
using System.Collections.Generic;

public class Solution {
    public List<string> removeInvalidParentheses(string data) {
        HashSet<string> result = new HashSet<string>();
        int minRemoved = int.MaxValue;
        Remove(data, 0, 0, 0, ref minRemoved, "", result);
        return new List<string>(result);
    }

    private void Remove(string s, int index, int leftCount, int rightCount, ref int minRemoved, string current, HashSet<string> result) {
        if (index == s.Length) {
            if (leftCount == rightCount) {
                if (minRemoved >= 0) {
                    result.Add(current);
                }
            }
            return;
        }

        char c = s[index];
        if (c == '(') {
            Remove(s, index + 1, leftCount, rightCount, ref minRemoved, current, result);
            Remove(s, index + 1, leftCount + 1, rightCount, ref minRemoved, current + '(', result);
        } else if (c == ')') {
            Remove(s, index + 1, leftCount, rightCount, ref minRemoved, current, result);
            if (leftCount > rightCount) {
                Remove(s, index + 1, leftCount, rightCount + 1, ref minRemoved, current + ')', result);
            }
        } else {
            Remove(s, index + 1, leftCount, rightCount, ref minRemoved, current + c, result);
        }
    }
}

